SELECT notice_id, title, content, author_name, publish_date, category, status, reg_date FROM erp_notice
AND (title LIKE '%' || #{keyword} || '%' OR author_name LIKE '%' || #{keyword} || '%')
ORDER BY reg_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT message_id, sender_name, receiver_name, title, content, send_date, read_date, status FROM erp_message
AND (title LIKE '%' || #{keyword} || '%' OR sender_name LIKE '%' || #{keyword} || '%' OR receiver_name LIKE '%' || #{keyword} || '%')
ORDER BY send_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT prayer_id, member_name, title, content, status, reg_date FROM erp_prayer
AND (title LIKE '%' || #{keyword} || '%' OR member_name LIKE '%' || #{keyword} || '%')
ORDER BY reg_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT newsletter_id, title, content, author_name, publish_date, status, reg_date FROM erp_newsletter
AND (title LIKE '%' || #{keyword} || '%' OR author_name LIKE '%' || #{keyword} || '%')
ORDER BY publish_date DESC LIMIT #{limit} OFFSET #{offset}
